        var triplet: Double = (1.0).toDouble() / (3.0).toDouble()
        when (note.ornament)
        {
            com.omnifret.gplayer.model.NoteOrnament.Turn -> 
            {
                ornamentNoteKeys = com.omnifret.gplayer.collections.DoubleList(
                    noteKey + com.omnifret.gplayer.midi.MidiFileGenerator._ornamentKeysUp[(index).toInt()], noteKey, noteKey + com.omnifret.gplayer.midi.MidiFileGenerator.ornamentKeysDown[(index).toInt()])
                
                ornamentNoteDurations = com.omnifret.gplayer.collections.DoubleList(
                    com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.Sixteenth) * triplet, com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.Sixteenth) * triplet, com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.Sixteenth) * triplet)
                
            }
            com.omnifret.gplayer.model.NoteOrnament.InvertedTurn -> 
            {
                ornamentNoteKeys = com.omnifret.gplayer.collections.DoubleList(
                    noteKey + com.omnifret.gplayer.midi.MidiFileGenerator.ornamentKeysDown[(index).toInt()], noteKey, noteKey + com.omnifret.gplayer.midi.MidiFileGenerator._ornamentKeysUp[(index).toInt()])
                
                ornamentNoteDurations = com.omnifret.gplayer.collections.DoubleList(
                    com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.Sixteenth) * triplet, com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.Sixteenth) * triplet, com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.Sixteenth) * triplet)
                
            }
            com.omnifret.gplayer.model.NoteOrnament.UpperMordent -> 
            {
                ornamentNoteKeys = com.omnifret.gplayer.collections.DoubleList(
                    noteKey, noteKey + com.omnifret.gplayer.midi.MidiFileGenerator._ornamentKeysUp[(index).toInt()])
                
                ornamentNoteDurations = com.omnifret.gplayer.collections.DoubleList(
                    com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.ThirtySecond), com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.ThirtySecond))
                
            }
            com.omnifret.gplayer.model.NoteOrnament.LowerMordent -> 
            {
                ornamentNoteKeys = com.omnifret.gplayer.collections.DoubleList(
                    noteKey, noteKey + com.omnifret.gplayer.midi.MidiFileGenerator.ornamentKeysDown[(index).toInt()])
                
                ornamentNoteDurations = com.omnifret.gplayer.collections.DoubleList(
                    com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.ThirtySecond), com.omnifret.gplayer.midi.MidiUtils.toTicks(com.omnifret.gplayer.model.Duration.ThirtySecond))
                
            }
            else -> 
            {
                return
            }
        }
        var ornamentDurationFactor: Double = 1.0
        if (noteDuration < com.omnifret.gplayer.midi.MidiUtils.QuarterTime)
        {
            ornamentDurationFactor = noteDuration / com.omnifret.gplayer.midi.MidiUtils.QuarterTime
        }
        paramvelocity -= com.omnifret.gplayer.midi.MidiUtils.VelocityIncrement
        var totalOrnamentDuration: Double = 0.0
        if (true) {
            var i: Double = 0.0
            
