                var realDuration: Double = ornamentNoteDurations[(i).toInt()] * ornamentDurationFactor
                this._handler.addNote(
                    track.index
                    , 
                    paramnoteStart
                    , 
                    realDuration
                    , 
                    ornamentNoteKeys[(i).toInt()]
                    , 
                    paramvelocity
                    , 
                    channel
                
                )
                paramnoteStart += realDuration
                totalOrnamentDuration += realDuration
                i++
            }
        }
        var remaining: Double = noteDuration - totalOrnamentDuration
        this._handler.addNote(
            track.index
            , 
            paramnoteStart
            , 
            remaining
            , 
            noteKey
            , 
            paramvelocity
            , 
            channel
        
        )
    }
    
    /**
     */
    private fun _getNoteDuration(note: com.omnifret.gplayer.model.Note, beatPlayDuration: Double, tempoOnBeatStart: Double): com.omnifret.gplayer.midi.MidiNoteDuration{
        var durationWithEffects: com.omnifret.gplayer.midi.MidiNoteDuration = com.omnifret.gplayer.midi.MidiNoteDuration()
        var defaultBeatDuration: Double = com.omnifret.gplayer.midi.MidiUtils.toTicks(note.beat.duration)
        durationWithEffects.beatDurationFactor = beatPlayDuration / defaultBeatDuration
        durationWithEffects.noteOnly = beatPlayDuration
        durationWithEffects.untilTieOrSlideEnd = beatPlayDuration
        durationWithEffects.letRingEnd = beatPlayDuration
        if (note.isDead)
        {
            durationWithEffects.noteOnly = this._applyStaticDuration(com.omnifret.gplayer.midi.MidiFileGenerator._defaultDurationDead, beatPlayDuration, tempoOnBeatStart)
            durationWithEffects.untilTieOrSlideEnd = durationWithEffects.noteOnly
            durationWithEffects.letRingEnd = durationWithEffects.noteOnly
            return durationWithEffects
        }
        if (note.isPalmMute)
        {
            durationWithEffects.noteOnly = this._applyStaticDuration(com.omnifret.gplayer.midi.MidiFileGenerator._defaultDurationPalmMute, beatPlayDuration, tempoOnBeatStart)
            durationWithEffects.untilTieOrSlideEnd = durationWithEffects.noteOnly
            durationWithEffects.letRingEnd = durationWithEffects.noteOnly
            return durationWithEffects
        }
        if (note.isStaccato)
        {
            durationWithEffects.noteOnly = (((beatPlayDuration / (2.0).toDouble())).toInt() or 0).toDouble()
            durationWithEffects.untilTieOrSlideEnd = durationWithEffects.noteOnly
            durationWithEffects.letRingEnd = durationWithEffects.noteOnly
            return durationWithEffects
        }
        if (note.isTieOrigin)
        {
            var endNote: com.omnifret.gplayer.model.Note = note.tieDestination!!
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(endNote)))
            {
                if (!note.isTieDestination)
                {
                    var startTick: Double = note.beat.absolutePlaybackStart
                    var tieDestinationDuration: com.omnifret.gplayer.midi.MidiNoteDuration = this._getNoteDuration(endNote, endNote.beat.playbackDuration, tempoOnBeatStart)
                    var endTick: Double = endNote.beat.absolutePlaybackStart + tieDestinationDuration.untilTieOrSlideEnd
                    durationWithEffects.untilTieOrSlideEnd = endTick - startTick
                }
                else 
                {
                    var tieDestinationDuration: com.omnifret.gplayer.midi.MidiNoteDuration = this._getNoteDuration(endNote, endNote.beat.playbackDuration, tempoOnBeatStart)
                    durationWithEffects.untilTieOrSlideEnd = beatPlayDuration + tieDestinationDuration.untilTieOrSlideEnd
                }
            }
        }
        else if (note.slideOutType == com.omnifret.gplayer.model.SlideOutType.Legato)
        {
            var endNote: com.omnifret.gplayer.model.Note = note.slideTarget!!
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(endNote)))
            {
                var startTick: Double = note.beat.absolutePlaybackStart
                var slideTargetDuration: com.omnifret.gplayer.midi.MidiNoteDuration = this._getNoteDuration(endNote, endNote.beat.playbackDuration, tempoOnBeatStart)
                var endTick: Double = endNote.beat.absolutePlaybackStart + slideTargetDuration.untilTieOrSlideEnd
                durationWithEffects.untilTieOrSlideEnd = endTick - startTick
            }
        }
        if (note.isLetRing && this._settings.notation.notationMode == com.omnifret.gplayer.NotationMode.GuitarPro)
        {
            var lastLetRingBeat: com.omnifret.gplayer.model.Beat = note.beat
            var letRingEnd: Double = 0.0
            var maxDuration: Double = note.beat.voice.bar.masterBar.calculateDuration()
            while (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(lastLetRingBeat.nextBeat)))
            {
                var next: com.omnifret.gplayer.model.Beat = lastLetRingBeat.nextBeat!!
                if (next.isRest)
                {
                    break
                }
                if (note.isStringed && next.hasNoteOnString(note.string))
                {
                    break
                }
                lastLetRingBeat = lastLetRingBeat.nextBeat!!
                letRingEnd = lastLetRingBeat.absolutePlaybackStart - note.beat.absolutePlaybackStart + lastLetRingBeat.playbackDuration
                if (letRingEnd > maxDuration)
                {
                    letRingEnd = maxDuration
                    break
                }
            }
            if (lastLetRingBeat == note.beat)
            {
                durationWithEffects.letRingEnd = beatPlayDuration
            }
            else 
            {
                durationWithEffects.letRingEnd = letRingEnd
            }
        }
        else 
        {
            durationWithEffects.letRingEnd = durationWithEffects.untilTieOrSlideEnd
        }
        return durationWithEffects
    }
    
    /**
     */
    private fun _applyStaticDuration(duration: Double, maximum: Double, tempo: Double): Double{
        var value: Double = ((((tempo * duration) / com.omnifret.gplayer.model.BendPoint.MaxPosition)).toInt() or 0).toDouble()
        return com.omnifret.gplayer.core.ecmaScript.Math.min(value, maximum)
    }
    
    /**
     */
