            }
            com.omnifret.gplayer.model.FadeType.FadeOut -> 
            {
                this._generateFadeSteps(track, beatStart, beatDuration, com.omnifret.gplayer.midi.MidiFileGenerator._toChannelShort(track.playbackInfo.volume), 0.0)
            }
            com.omnifret.gplayer.model.FadeType.VolumeSwell -> 
            {
                var half: Double = (((beatDuration / (2.0).toDouble())).toInt() or 0).toDouble()
                this._generateFadeSteps(track, beatStart, half, 0.0, com.omnifret.gplayer.midi.MidiFileGenerator._toChannelShort(track.playbackInfo.volume))
                this._generateFadeSteps(track, beatStart + half, half, com.omnifret.gplayer.midi.MidiFileGenerator._toChannelShort(track.playbackInfo.volume), 0.0)
            }
