    /**
     */
    private fun _generateFadeSteps(track: com.omnifret.gplayer.model.Track, start: Double, duration: Double, startVolume: Double, endVolume: Double): Unit{
        var paramduration = duration
        var tickStep: Double = 120.0
        paramduration = (((paramduration * (0.8).toDouble())).toInt() or 0).toDouble()
        var volumeFactor: Double = (endVolume - startVolume) / paramduration
        var steps: Double = (((paramduration / tickStep + 1.0)).toInt() or 0).toDouble()
        var endTick: Double = start + paramduration
        if (true) {
            var i: Double = 0.0
            
            while(i < steps){
                var isLast: Boolean = i == steps - (1.0).toDouble()
                var tick: Double = if(isLast)  endTick else start + i * tickStep
                var volume: Double = if(isLast)  endVolume else com.omnifret.gplayer.core.ecmaScript.Math.round(startVolume + (tick - start) * volumeFactor)
                this._handler.addControlChange(track.index, tick, track.playbackInfo.primaryChannel, com.omnifret.gplayer.midi.ControllerType.VolumeCoarse, volume)
                this._handler.addControlChange(track.index, tick, track.playbackInfo.secondaryChannel, com.omnifret.gplayer.midi.ControllerType.VolumeCoarse, volume)
                i++
            }
        }
    }
    
    /**
     */
