    public var vibratoResolution: Double = 16.0
    
    
    /**
     */
    private fun _generateVibratorWithParams(noteStart: Double, 
    noteDuration: Double, 
    phaseLength: Double, 
    bendBase: Double, 
    bendAmplitude: Double, 
    addBend: ((arg1: Double, arg2: Double) -> Unit)): Unit{
        var paramnoteStart = noteStart
        var resolution: Double = this.vibratoResolution
        var phaseHalf: Double = (((phaseLength / (2.0).toDouble())).toInt() or 0).toDouble()
        var noteEnd: Double = paramnoteStart + noteDuration
        while (paramnoteStart < noteEnd)
        {
            var phase: Double = 0.0
            var phaseDuration: Double = if(paramnoteStart + phaseLength < noteEnd)  phaseLength else noteEnd - paramnoteStart
            while (phase < phaseDuration)
            {
                var bend: Double = bendBase + bendAmplitude * com.omnifret.gplayer.core.ecmaScript.Math.sin((phase * com.omnifret.gplayer.core.ecmaScript.Math.PI) / phaseHalf)
                addBend((((paramnoteStart + phase)).toInt() or 0).toDouble(), com.omnifret.gplayer.midi.MidiFileGenerator.getPitchWheel(bend))
                phase += resolution
            }
            paramnoteStart += phaseLength
        }
        addBend(((noteEnd).toInt() or 0).toDouble(), com.omnifret.gplayer.midi.MidiFileGenerator.getPitchWheel(bendBase))
    }
    
    /**
     */
    private fun _generateSlide(note: com.omnifret.gplayer.model.Note, 
    noteStart: Double, 
