        var simpleSlideDurationOffset: Double = com.omnifret.gplayer.core.ecmaScript.Math.floor(com.omnifret.gplayer.model.BendPoint.MaxPosition * this._settings.player.slide.simpleSlideDurationRatio)
        var shiftSlideDurationOffset: Double = com.omnifret.gplayer.core.ecmaScript.Math.floor(com.omnifret.gplayer.model.BendPoint.MaxPosition * this._settings.player.slide.shiftSlideDurationRatio)
