    /**
     */
    private fun _generateBend(note: com.omnifret.gplayer.model.Note, 
    noteStart: Double, 
    noteDuration: com.omnifret.gplayer.midi.MidiNoteDuration, 
    noteKey: Double, 
    channel: Double, 
    tempoOnBeatStart: Double): Unit{
        var paramnoteStart = noteStart
        var bendPoints: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.BendPoint> = note.bendPoints!!
        var track: com.omnifret.gplayer.model.Track = note.beat.voice.bar.staff.track
        var addBend: ((arg1: Double, arg2: Double) -> Unit) = fun(tick: Double, value: Double): Unit{
            this._handler.addNoteBend(track.index, tick, channel, noteKey, value)
        }
        
        var finalBendValue: Double? = null
        var duration: Double
        if (note.isTieOrigin && this._settings.notation.extendBendArrowsOnTiedNotes)
        {
