    /**
     */
    private fun _generateWhammyOrBend(noteStart: Double, duration: Double, playedBendPoints: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.BendPoint>, tempoOnBeatStart: Double, addBend: ((arg1: Double, arg2: Double) -> Unit)): Unit{
        var ticksPerPosition: Double = duration / com.omnifret.gplayer.model.BendPoint.MaxPosition
        if (true) {
            var i: Double = 0.0
            
            while(i < playedBendPoints.length - (1.0).toDouble()){
                var currentPoint: com.omnifret.gplayer.model.BendPoint = playedBendPoints[(i).toInt()]
                var nextPoint: com.omnifret.gplayer.model.BendPoint = playedBendPoints[(i + 1.0).toInt()]
                var currentBendValue: Double = com.omnifret.gplayer.midi.MidiFileGenerator.getPitchWheel(currentPoint.value)
                var nextBendValue: Double = com.omnifret.gplayer.midi.MidiFileGenerator.getPitchWheel(nextPoint.value)
                var ticksBetweenPoints: Double = ticksPerPosition * (nextPoint.offset - currentPoint.offset)
                var tick: Double = noteStart + ticksPerPosition * currentPoint.offset
                this._generateBendValues(
                    tick
                    , 
                    ticksBetweenPoints
                    , 
                    currentBendValue
                    , 
                    nextBendValue
                    , 
                    tempoOnBeatStart
                    , 
                    addBend
                
                )
                i++
            }
        }
    }
    
    /**
     */
    private fun _generateBendValues(currentTick: Double, 
    ticksBetweenPoints: Double, 
    currentBendValue: Double, 
    nextBendValue: Double, 
    tempoOnBeatStart: Double, 
    addBend: ((arg1: Double, arg2: Double) -> Unit)): Unit{
        var paramcurrentBendValue = currentBendValue
        var paramcurrentTick = currentTick
        var millisBetweenPoints: Double = com.omnifret.gplayer.midi.MidiUtils.ticksToMillis(ticksBetweenPoints, tempoOnBeatStart)
        var numberOfSemitones: Double = com.omnifret.gplayer.core.ecmaScript.Math.abs(nextBendValue - paramcurrentBendValue) / com.omnifret.gplayer.midi.MidiFileGenerator._pitchValuePerSemitone
        var numberOfSteps: Double = com.omnifret.gplayer.core.ecmaScript.Math.max(com.omnifret.gplayer.midi.MidiFileGenerator._minBreakpointsPerSemitone * numberOfSemitones, millisBetweenPoints / com.omnifret.gplayer.midi.MidiFileGenerator._millisecondsPerBreakpoint)
        var ticksPerBreakpoint: Double = ticksBetweenPoints / numberOfSteps
        var pitchPerBreakpoint: Double = (nextBendValue - paramcurrentBendValue) / numberOfSteps
        var endTick: Double = paramcurrentTick + ticksBetweenPoints
        if (true) {
            var i: Double = 0.0
            
            while(i < numberOfSteps){
                addBend(((paramcurrentTick).toInt() or 0).toDouble(), com.omnifret.gplayer.core.ecmaScript.Math.round(paramcurrentBendValue))
                paramcurrentBendValue += pitchPerBreakpoint
                paramcurrentTick += ticksPerBreakpoint
                i++
            }
        }
        addBend(((endTick).toInt() or 0).toDouble(), nextBendValue)
    }
    
    /**
     */
    private fun _generateRasgueado(track: com.omnifret.gplayer.model.Track, 
    note: com.omnifret.gplayer.model.Note, 
    noteStart: Double, 
    noteKey: Double, 
    velocity: Double, 
    channel: Double, 
    rasgueadoInfo: com.omnifret.gplayer.midi.RasgueadoInfo): Unit{
        var tick: Double = noteStart
        if (true) {
            var i: Double = 0.0
            
            while(i < rasgueadoInfo.durations.length){
                var brushInfo: com.omnifret.gplayer.core.ecmaScript.Int32Array = rasgueadoInfo.brushInfos[(i).toInt()]
                var brushOffset: Double = if(note.isStringed && note.string <= brushInfo.length)  brushInfo[(note.string - (1.0).toDouble()).toInt()] else 0.0
                var duration: Double = rasgueadoInfo.durations[(i).toInt()].toDouble()
                this._handler.addNote(
                    track.index
                    , 
                    tick + brushOffset
                    , 
                    duration - brushOffset
                    , 
                    noteKey
                    , 
                    velocity
                    , 
                    channel
                
                )
                tick += duration
                i++
            }
        }
    }
    
    /**
     */
    private fun _generateTrill(note: com.omnifret.gplayer.model.Note, 
    noteStart: Double, 
    noteDuration: com.omnifret.gplayer.midi.MidiNoteDuration, 
    noteKey: Double, 
    dynamicValue: Double, 
    channel: Double): Unit{
        var track: com.omnifret.gplayer.model.Track = note.beat.voice.bar.staff.track
        var trillKey: Double = note.stringTuning + note.trillFret
        var trillLength: Double = com.omnifret.gplayer.midi.MidiUtils.toTicks(note.trillSpeed)
        var realKey: Boolean = true
        var tick: Double = noteStart
        var end: Double = noteStart + noteDuration.untilTieOrSlideEnd
        while (tick + 10.0 < end)
        {
            if (tick + trillLength >= end)
            {
                trillLength = end - tick
            }
            this._handler.addNote(
                track.index
                , 
                tick
                , 
                trillLength
                , 
                if(realKey)  noteKey else trillKey
                , 
                dynamicValue
                , 
                channel
            
            )
            realKey = !realKey
            tick += trillLength
        }
    }
    
    /**
     */
    private fun _generateTremoloPicking(note: com.omnifret.gplayer.model.Note, 
    noteStart: Double, 
    noteDuration: com.omnifret.gplayer.midi.MidiNoteDuration, 
    noteKey: Double, 
    dynamicValue: Double, 
    channel: Double): Unit{
        var track: com.omnifret.gplayer.model.Track = note.beat.voice.bar.staff.track
        var marks: Double = note.beat.tremoloPicking!!.marks
        if (marks == 0.0)
        {
            return
        }
        var tpLength: Double = note.beat.tremoloPicking!!.getDurationAsTicks(note.beat.duration) * noteDuration.beatDurationFactor
        var tick: Double = noteStart
        var end: Double = noteStart + noteDuration.untilTieOrSlideEnd
        while (tick + 10.0 < end)
        {
            if (tick + tpLength >= end)
            {
                tpLength = end - tick
            }
            this._handler.addNote(
                track.index
                , 
                tick
                , 
                tpLength
                , 
                noteKey
                , 
                dynamicValue
                , 
                channel
            
            )
            tick += tpLength
        }
    }
    
    /**
     */
    private fun _getRasgueadoInfo(beat: com.omnifret.gplayer.model.Beat, beatDuration: Double): com.omnifret.gplayer.midi.RasgueadoInfo?{
        if (!beat.hasRasgueado)
        {
            return null
        }
        var info: com.omnifret.gplayer.midi.RasgueadoInfo = com.omnifret.gplayer.midi.RasgueadoInfo()
        var rasgueadoPattern: com.omnifret.gplayer.collections.DoubleList = com.omnifret.gplayer.midi.MidiFileGenerator._rasgueadoDurations.get(beat.rasgueado)!!
        var patternDuration: Double = rasgueadoPattern.reduce(fun(p: Double, v: Double): Double{
            return p + v
        }
        , 0.0)
        info.durations = com.omnifret.gplayer.midi.MidiFileGenerator._rasgueadoDurations.get(beat.rasgueado)!!.map(fun(v: Double): Double{
            return (beatDuration * v) / patternDuration
        }
