        while (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(currentBeat)) && (tempo == -1.0 || program == -1.0)))
        {
            for (automation in beat.automations)
            {
                when (automation.type)
                {
                    com.omnifret.gplayer.model.AutomationType.Instrument -> 
                    {
                        program = automation.value
                    }
                    com.omnifret.gplayer.model.AutomationType.Tempo -> 
                    {
                        tempo = automation.value
                    }
                    else -> { }
                }
            }
            currentBeat = currentBeat!!.previousBeat
        }
        var track: com.omnifret.gplayer.model.Track = beat.voice.bar.staff.track
        var masterBar: com.omnifret.gplayer.model.MasterBar = beat.voice.bar.masterBar
