        }
        var positionRatio: Double = beat.playbackStart / masterBar.calculateDuration()
        for (automation in masterBar.tempoAutomations)
        {
            if (automation.ratioPosition <= positionRatio)
            {
                tempo = automation.value
            }
            else 
            {
                break
            }
        }
        if (program == -1.0)
        {
            program = track.playbackInfo.program
        }
        var volume: Double = track.playbackInfo.volume
        this._generateTrack(track)
        this._handler.addTimeSignature(0.0, masterBar.timeSignatureNumerator, masterBar.timeSignatureDenominator)
        this._handler.addTempo(0.0, tempo)
        var volumeCoarse: Double = com.omnifret.gplayer.midi.MidiFileGenerator._toChannelShort(volume)
        this._handler.addControlChange(0.0, 0.0, track.playbackInfo.primaryChannel, com.omnifret.gplayer.midi.ControllerType.VolumeCoarse, volumeCoarse)
        this._handler.addControlChange(0.0, 0.0, track.playbackInfo.secondaryChannel, com.omnifret.gplayer.midi.ControllerType.VolumeCoarse, volumeCoarse)
